#include <ArduinoJson.h>

// Pin Configuration
#define MOISTURE_SENSOR_PIN {{.moisturePin}}
#define PUMP_RELAY_PIN {{.pumpPin}}
#define STATUS_LED_PIN {{.ledPin}}

// Threshold Configuration
#define DRY_THRESHOLD {{.dryThreshold}} // Water when moisture < this %
#define WET_THRESHOLD {{.wetThreshold}} // Stop watering when moisture > this %
#define PUMP_DURATION {{.pumpDuration}} // Maximum pump runtime in seconds
#define CHECK_INTERVAL {{.checkInterval}} // Check interval in minutes

// Sensor Calibration
#define SENSOR_DRY_VALUE {{.sensorCalibrationDry}} // Analog reading when dry
#define SENSOR_WET_VALUE {{.sensorCalibrationWet}} // Analog reading when wet

// System State
enum SystemState {
  IDLE,
  WATERING,
  WAITING
};

SystemState current_state = IDLE;
unsigned long last_check_time = 0;
unsigned long pump_start_time = 0;
int current_moisture = 0;
int moisture_history[10]; // Store last 10 readings for averaging
int history_index = 0;
bool pump_active = false;

// Function prototypes
int read_moisture();
int get_average_moisture();
void control_pump(bool turn_on);
void update_status_led();
void log_system_status();

void setup() {
  Serial.begin(115200);
  Serial.println("Soil Moisture Monitor with Pump Control Starting...");

  // Initialize pins
  pinMode(MOISTURE_SENSOR_PIN, INPUT);
  pinMode(PUMP_RELAY_PIN, OUTPUT);
  pinMode(STATUS_LED_PIN, OUTPUT);

  // Initialize outputs
  digitalWrite(PUMP_RELAY_PIN, LOW); // Pump OFF
  digitalWrite(STATUS_LED_PIN, LOW); // LED OFF

  // Initialize moisture history
  for (int i = 0; i < 10; i++) {
    moisture_history[i] = 0;
  }

  // Wait for sensor to stabilize
  delay(2000);

  // Take initial reading
  current_moisture = read_moisture();
  for (int i = 0; i < 10; i++) {
    moisture_history[i] = current_moisture;
  }

  Serial.print("Configuration:");
  Serial.print(" Dry Threshold: ");
  Serial.print(DRY_THRESHOLD);
  Serial.print("%, Wet Threshold: ");
  Serial.print(WET_THRESHOLD);
  Serial.print("%, Pump Duration: ");
  Serial.print(PUMP_DURATION);
  Serial.print("s, Check Interval: ");
  Serial.print(CHECK_INTERVAL);
  Serial.println("min");

  Serial.print("Sensor Calibration - Dry: ");
  Serial.print(SENSOR_DRY_VALUE);
  Serial.print(", Wet: ");
  Serial.println(SENSOR_WET_VALUE);

  Serial.print("Initial moisture: ");
  Serial.print(current_moisture);
  Serial.println("%");
}

void loop() {
  unsigned long current_time = millis();

  // Check moisture at specified intervals
  if (current_time - last_check_time >= (CHECK_INTERVAL * 60000UL)) {
    last_check_time = current_time;

    // Read and average moisture
    current_moisture = read_moisture();
    moisture_history[history_index] = current_moisture;
    history_index = (history_index + 1) % 10;

    int avg_moisture = get_average_moisture();

    Serial.print("Moisture check - Current: ");
    Serial.print(current_moisture);
    Serial.print("%, Average: ");
    Serial.print(avg_moisture);
    Serial.println("%");

    // State machine logic
    switch (current_state) {
      case IDLE:
        if (avg_moisture < DRY_THRESHOLD) {
          Serial.println("Soil is dry - starting watering");
          current_state = WATERING;
          control_pump(true);
          pump_start_time = current_time;
        }
        break;

      case WATERING:
        // Check if moisture is sufficient or max duration reached
        if (avg_moisture >= WET_THRESHOLD || 
            (current_time - pump_start_time >= (PUMP_DURATION * 1000UL))) {

          if (avg_moisture >= WET_THRESHOLD) {
            Serial.println("Soil is wet enough - stopping watering");
          } else {
            Serial.println("Maximum pump duration reached - stopping watering");
          }

          control_pump(false);
          current_state = WAITING;
        }
        break;

      case WAITING:
        // Wait for next check cycle
        current_state = IDLE;
        break;
    }

    log_system_status();
  }

  // Update status LED
  update_status_led();

  // Safety check: never let pump run more than max duration
  if (pump_active && (current_time - pump_start_time >= (PUMP_DURATION * 1000UL))) {
    Serial.println("SAFETY: Maximum pump duration exceeded - forcing pump OFF");
    control_pump(false);
    current_state = WAITING;
  }

  delay(1000); // Small delay to prevent overwhelming the system
}

int read_moisture() {
  // Read analog value from moisture sensor
  int raw_value = analogRead(MOISTURE_SENSOR_PIN);

  // Map raw value to percentage (inverted because dry = high value)
  int percentage = map(raw_value, SENSOR_DRY_VALUE, SENSOR_WET_VALUE, 0, 100);

  // Constrain to 0-100 range
  if (percentage < 0) percentage = 0;
  if (percentage > 100) percentage = 100;

  return percentage;
}

int get_average_moisture() {
  // Calculate average of last 10 readings
  long sum = 0;
  for (int i = 0; i < 10; i++) {
    sum += moisture_history[i];
  }
  return sum / 10;
}

void control_pump(bool turn_on) {
  if (turn_on && !pump_active) {
    Serial.println("Pump ON");
    digitalWrite(PUMP_RELAY_PIN, HIGH);
    pump_active = true;
  } else if (!turn_on && pump_active) {
    Serial.println("Pump OFF");
    digitalWrite(PUMP_RELAY_PIN, LOW);
    pump_active = false;
  }
}

void update_status_led() {
  // LED patterns based on system state
  static unsigned long led_update_time = 0;
  static bool led_state = false;

  unsigned long current_time = millis();

  switch (current_state) {
    case IDLE:
      // Slow blink when idle
      if (current_time - led_update_time >= 2000) {
        led_state = !led_state;
        digitalWrite(STATUS_LED_PIN, led_state);
        led_update_time = current_time;
      }
      break;

    case WATERING:
      // Fast blink when watering
      if (current_time - led_update_time >= 500) {
        led_state = !led_state;
        digitalWrite(STATUS_LED_PIN, led_state);
        led_update_time = current_time;
      }
      break;

    case WAITING:
      // Solid LED when waiting
      digitalWrite(STATUS_LED_PIN, HIGH);
      break;
  }
}

void log_system_status() {
  // Create JSON status for potential MQTT/web integration
  StaticJsonDocument<200> doc;
  doc["timestamp"] = millis();
  doc["moisture"] = current_moisture;
  doc["average_moisture"] = get_average_moisture();
  doc["state"] = (int)current_state;
  doc["pump_active"] = pump_active;
  doc["dry_threshold"] = DRY_THRESHOLD;
  doc["wet_threshold"] = WET_THRESHOLD;

  String status_json;
  serializeJson(doc, status_json);

  // Output JSON to serial (could be sent to MQTT in future)
  Serial.print("Status: ");
  Serial.println(status_json);
}
